  1→import React, { useState, useEffect } from 'react';
  2→import { User } from '../types';
  3→import { Fuel, Check, CreditCard, Loader2, Droplet, Database, ArrowLeft, ShieldCheck, Lock, Infinity, CheckCircle2, FileText, Download, XCircle, LayoutDashboard, RefreshCcw, Wrench } from 'lucide-react';
  4→import jsPDF from 'jspdf';
  5→
  6→interface Props {
  7→  onBack: () => void;
  8→  onRecharge: (amount: number, planLevel: 'free' | 'pro' | 'enterprise') => void;
  9→  user: User | null;
 10→  onNavigate?: (view: string) => void;
 11→  initialPackId?: number | null;
 12→}
 13→
 14→const Recharge: React.FC<Props> = ({ onBack, onRecharge, user, onNavigate, initialPackId }) => {
 15→  const [viewMode, setViewMode] = useState<'list' | 'checkout' | 'result'>('list');
 16→  const [paymentStatus, setPaymentStatus] = useState<'idle' | 'success' | 'error'>('idle');
 17→  const [selectedPack, setSelectedPack] = useState<typeof packs[0] | null>(null);
 18→  const [isProcessing, setIsProcessing] = useState(false);
 19→  const [invoiceId, setInvoiceId] = useState<string>('');
 20→
 21→  const packs = [
 22→    {
 23→      id: 1,
 24→      name: "Le Jerrican",
 25→      amount: 50,
 26→      price: 15,
 27→      icon: <Droplet size={32} />,
 28→      popular: false,
 29→      level: 'free' as const,
 30→      features: ["Idéal pour un audit ponctuel", "Valable 1 an"]
 31→    },
 32→    {
 33→      id: 2,
 34→      name: "La Pompe",
 35→      amount: 200,
 36→      price: 49,
 37→      icon: <Fuel size={32} />,
 38→      popular: true,
 39→      level: 'pro' as const,
 40→      features: ["Pour les optimisations régulières", "Support prioritaire", "+10% Bonus offert"]
 41→    },
 42→    {
 43→      id: 3,
 44→      name: "La Citerne",
 45→      amount: 1000,
 46→      price: 199,
 47→      icon: <Database size={32} />,
 48→      popular: false,
 49→      level: 'enterprise' as const,
 50→      features: ["Usage intensif / Agence", "Accès API Beta", "+20% Bonus offert"]
 51→    }
 52→  ];
 53→
 54→  // Effet pour sélectionner automatiquement un pack si initialPackId est fourni
 55→  useEffect(() => {
 56→    if (initialPackId) {
 57→        const targetPack = packs.find(p => p.id === initialPackId);
 58→        if (targetPack) {
 59→            setSelectedPack(targetPack);
 60→            setViewMode('checkout');
 61→        }
 62→    }
 63→  }, [initialPackId]);
 64→
 65→  const handleSelectPack = (pack: typeof packs[0]) => {
 66→    setSelectedPack(pack);
 67→    setViewMode('checkout');
 68→    window.scrollTo({ top: 0, behavior: 'smooth' });
 69→  };
 70→
 71→  const handleConfirmPayment = () => {
 72→    if (!selectedPack) return;
 73→    setIsProcessing(true);
 74→    setPaymentStatus('idle');
 75→    
 76→    // Simulation délai paiement et résultat aléatoire (90% de succès pour l'UX)
 77→    setTimeout(() => {
 78→      const isSuccess = Math.random() > 0.1;
 79→      
 80→      if (isSuccess) {
 81→        onRecharge(selectedPack.amount, selectedPack.level);
 82→        const newInvoiceId = `INV-${new Date().getFullYear()}-${Math.floor(Math.random() * 10000).toString().padStart(4, '0')}`;
 83→        setInvoiceId(newInvoiceId);
 84→        setPaymentStatus('success');
 85→      } else {
 86→        setPaymentStatus('error');
 87→      }
 88→      
 89→      setIsProcessing(false);
 90→      setViewMode('result');
 91→      window.scrollTo({ top: 0, behavior: 'smooth' });
 92→    }, 2000);
 93→  };
 94→
 95→  const generateInvoicePDF = () => {
 96→    if (!selectedPack || !user) return;
 97→
 98→    const doc = new jsPDF();
 99→    const priceHT = selectedPack.price;
100→    const tva = priceHT * 0.20;
101→    const totalTTC = priceHT + tva;
102→    const date = new Date().toLocaleDateString('fr-FR');
103→
104→    // Header
105→    doc.setFontSize(22);
106→    doc.setFont("helvetica", "bold");
107→    doc.text("CitedBy.ai", 20, 20);
108→    
109→    doc.setFontSize(10);
110→    doc.setFont("helvetica", "normal");
111→    doc.text("Facture N° " + invoiceId, 20, 30);
112→    doc.text("Date : " + date, 20, 35);
113→
114→    // Client Info
115→    doc.text("Facturé à :", 140, 30);
116→    doc.setFont("helvetica", "bold");
117→    doc.text(user.name || "Client", 140, 35);
118→    doc.setFont("helvetica", "normal");
119→    doc.text(user.email || "", 140, 40);
120→
121→    // Line Items Header
122→    doc.line(20, 55, 190, 55);
123→    doc.setFont("helvetica", "bold");
124→    doc.text("Description", 20, 62);
125→    doc.text("Quantité", 120, 62);
126→    doc.text("Montant HT", 160, 62);
127→    doc.line(20, 66, 190, 66);
128→
129→    // Item
130→    doc.setFont("helvetica", "normal");
131→    doc.text(`Pack GTO Gas: ${selectedPack.name} (${selectedPack.amount} crédits)`, 20, 75);
132→    doc.text("1", 125, 75);
133→    doc.text(`${priceHT.toFixed(2)} €`, 160, 75);
134→
135→    // Totals
136→    doc.line(20, 90, 190, 90);
137→    doc.text("Sous-total HT :", 130, 100);
138→    doc.text(`${priceHT.toFixed(2)} €`, 160, 100);
139→    
140→    doc.text("TVA (20%) :", 130, 107);
141→    doc.text(`${tva.toFixed(2)} €`, 160, 107);
142→
143→    doc.setFont("helvetica", "bold");
144→    doc.setFontSize(12);
145→    doc.text("Total TTC :", 130, 117);
146→    doc.text(`${totalTTC.toFixed(2)} €`, 160, 117);
147→
148→    // Footer
149→    doc.setFontSize(8);
150→    doc.setFont("helvetica", "italic");
151→    doc.text("Merci de votre confiance. Cette facture a été réglée par carte bancaire.", 20, 140);
152→    doc.text("CitedBy Inc. - 123 Avenue de l'IA, Paris, France - SIRET 123 456 789", 20, 280);
153→
154→    doc.save(`Facture_${invoiceId}.pdf`);
155→  };
156→
157→  const renderList = () => (
158→    <div className="animate-in fade-in slide-in-from-left duration-500">
159→        <div className="text-center mb-16">
160→            <div className="inline-flex items-center justify-center w-16 h-16 bg-accent/20 rounded-2xl mb-6 text-accent border border-accent/20 shadow-[0_0_30px_rgba(168,85,247,0.2)]">
161→            <Fuel size={32} />
162→            </div>
