168→            </p>
169→        </div>
170→
171→        <div className="grid md:grid-cols-3 gap-8 max-w-5xl mx-auto">
172→            {packs.map((pack) => (
173→            <div 
174→                key={pack.id} 
175→                className={`relative bg-[#0f1115] border rounded-2xl p-8 flex flex-col transition-all duration-300 hover:transform hover:-translate-y-2 ${
176→                pack.popular 
177→                    ? 'border-accent shadow-[0_0_40px_rgba(168,85,247,0.15)] scale-105 z-10'
178→                    : 'border-white/10 hover:border-white/20'
179→                }`}
180→            >
181→                {pack.popular && (
182→                <div className="absolute -top-4 left-1/2 -translate-x-1/2 bg-accent text-white font-bold text-xs px-4 py-1 rounded-full uppercase tracking-wider">
183→                    Meilleure Offre
184→                </div>
185→                )}
186→
187→                <div className={`w-12 h-12 rounded-xl flex items-center justify-center mb-6 ${pack.popular ? 'bg-accent/20 text-accent' : 'bg-white/5 text-gray-400'}`}>
188→                {pack.icon}
189→                </div>
190→
191→                <h3 className="text-xl font-bold text-white mb-2">{pack.name}</h3>
192→                <div className="flex items-baseline gap-1 mb-6">
193→                <span className="text-4xl font-serif font-bold text-white">{pack.amount}</span>
194→                <span className="text-sm text-gray-400 font-medium">Gas</span>
195→                </div>
196→
197→                <ul className="space-y-3 mb-8 flex-1">
198→                {pack.features.map((feat, i) => (
199→                    <li key={i} className="flex items-start gap-3 text-sm text-gray-300">
200→                    <Check size={16} className={`mt-0.5 ${pack.popular ? 'text-accent' : 'text-gray-500'}`} />
201→                    {feat}
202→                    </li>
203→                ))}
204→                </ul>
205→
206→                <div className="border-t border-white/10 pt-6 mb-6">
207→                <div className="flex justify-between items-center mb-2">
208→                    <span className="text-gray-400">Prix HT</span>
209→                    <span className="text-xl font-bold text-white">{pack.price}€</span>
210→                </div>
211→                </div>
212→
213→                <button
214→                onClick={() => handleSelectPack(pack)}
215→                className={`w-full py-3.5 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${
216→                    pack.popular 
217→                    ? 'bg-accent hover:bg-purple-400 text-white shadow-lg shadow-accent/20'
218→                    : 'bg-gradient-to-r from-purple-500 to-violet-600 text-white hover:from-purple-400 hover:to-violet-500'
219→                }`}
220→                >
221→                    <CreditCard size={18} /> Acheter
222→                </button>
223→            </div>
224→            ))}
225→        </div>
226→
227→        <p className="text-center text-gray-500 text-xs mt-12">
228→            Paiement sécurisé via Stripe • Facture disponible instantanément • TVA non incluse
229→        </p>
230→    </div>
231→  );
232→
